import{_ as s,o as a,c as n,a2 as t}from"./chunks/framework.CuteRReP.js";const h=JSON.parse('{"title":"cm-jtbd","description":"Customer discovery framework using Jobs-To-Be-Done theory — JTBD interviews, canvas, and opportunity scoring for evidence-based product decisions.","frontmatter":{"title":"cm-jtbd","description":"Customer discovery framework using Jobs-To-Be-Done theory — JTBD interviews, canvas, and opportunity scoring for evidence-based product decisions.","keywords":["cm-jtbd","cody master","ai skill"],"robots":"index, follow"},"headers":[],"relativePath":"skills/cm-jtbd.md","filePath":"skills/cm-jtbd.md"}'),o={name:"skills/cm-jtbd.md"};function r(i,e,l,p,c,d){return a(),n("div",null,[...e[0]||(e[0]=[t(`<blockquote><p><strong>📋 Full Skill Source</strong> — This is the complete, unedited SKILL.md file. Nothing is hidden or summarized.</p></blockquote><p><a href="./">← Back to Skills Library</a></p><h1 id="jobs-to-be-done-—-customer-discovery-framework" tabindex="-1">Jobs-To-Be-Done — Customer Discovery Framework <a class="header-anchor" href="#jobs-to-be-done-—-customer-discovery-framework" aria-label="Permalink to &quot;Jobs-To-Be-Done — Customer Discovery Framework&quot;">​</a></h1><blockquote><p><strong>Understand the job, not the customer.</strong> People don&#39;t buy products — they hire them to get a job done.</p></blockquote><h2 id="when-to-use" tabindex="-1">When to Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to Use&quot;">​</a></h2><ul><li>Before designing a new feature or product</li><li>When existing features aren&#39;t converting or being used</li><li>Alongside <code>cm-brainstorm-idea</code> for deep customer context</li><li>User mentions: &quot;customer discovery&quot;, &quot;JTBD&quot;, &quot;what do customers want&quot;, &quot;product-market fit&quot;, &quot;why are users churning&quot;</li></ul><h2 id="the-jtbd-framework" tabindex="-1">The JTBD Framework <a class="header-anchor" href="#the-jtbd-framework" aria-label="Permalink to &quot;The JTBD Framework&quot;">​</a></h2><h3 id="job-statement-formula" tabindex="-1">Job Statement Formula <a class="header-anchor" href="#job-statement-formula" aria-label="Permalink to &quot;Job Statement Formula&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>When [SITUATION], I want to [MOTIVATION], so I can [EXPECTED OUTCOME]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="three-job-dimensions" tabindex="-1">Three Job Dimensions <a class="header-anchor" href="#three-job-dimensions" aria-label="Permalink to &quot;Three Job Dimensions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Dimension</th><th>Definition</th><th>Example</th></tr></thead><tbody><tr><td><strong>Functional</strong></td><td>The core task to accomplish</td><td>&quot;Get from A to B quickly&quot;</td></tr><tr><td><strong>Social</strong></td><td>How the person wants to be perceived</td><td>&quot;Be seen as a reliable professional&quot;</td></tr><tr><td><strong>Emotional</strong></td><td>How the person wants to feel</td><td>&quot;Feel confident in my decision&quot;</td></tr></tbody></table><h2 id="process" tabindex="-1">Process <a class="header-anchor" href="#process" aria-label="Permalink to &quot;Process&quot;">​</a></h2><h3 id="phase-1-job-discovery-interviews" tabindex="-1">Phase 1: Job Discovery (Interviews) <a class="header-anchor" href="#phase-1-job-discovery-interviews" aria-label="Permalink to &quot;Phase 1: Job Discovery (Interviews)&quot;">​</a></h3><ol><li>Recruit 5-8 recent customers (ideally within 90 days of purchase)</li><li>Use the Switch Interview technique — ask about the moment they decided to switch/buy</li><li>Key questions: <ul><li>&quot;Walk me through the day you decided to [buy/switch/start using X]&quot;</li><li>&quot;What were you doing before that solution existed?&quot;</li><li>&quot;What was the first thing you tried? Why didn&#39;t that work?&quot;</li><li>&quot;What almost stopped you from switching?&quot;</li></ul></li><li>Record patterns: triggers → anxiety → progress → outcomes</li></ol><h3 id="phase-2-jtbd-canvas" tabindex="-1">Phase 2: JTBD Canvas <a class="header-anchor" href="#phase-2-jtbd-canvas" aria-label="Permalink to &quot;Phase 2: JTBD Canvas&quot;">​</a></h3><p>For each major job discovered, complete the canvas:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>JOB STATEMENT:</span></span>
<span class="line"><span>When [situation], I want to [motivation], so I can [outcome]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>FUNCTIONAL DIMENSION: [core task]</span></span>
<span class="line"><span>SOCIAL DIMENSION:     [perception goal]</span></span>
<span class="line"><span>EMOTIONAL DIMENSION:  [feeling goal]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>FORCES PUSHING TO HIRE:</span></span>
<span class="line"><span>(+) Push: [what makes them switch from current solution]</span></span>
<span class="line"><span>(+) Pull: [what attracts them to new solution]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>FORCES RESISTING HIRE:</span></span>
<span class="line"><span>(-) Anxiety: [fears about new solution]</span></span>
<span class="line"><span>(-) Habit: [attachment to old solution]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>COMPETING SOLUTIONS CURRENTLY HIRED:</span></span>
<span class="line"><span>1. [direct competitor or workaround]</span></span>
<span class="line"><span>2. [indirect solution]</span></span>
<span class="line"><span>3. [do-nothing option]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>OUTCOME METRICS (how customer measures success):</span></span>
<span class="line"><span>- Speed: [e.g., &quot;get answer in &lt;5 minutes&quot;]</span></span>
<span class="line"><span>- Accuracy: [e.g., &quot;zero errors in the output&quot;]</span></span>
<span class="line"><span>- Effort: [e.g., &quot;no manual steps required&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br></div></div><h3 id="phase-3-opportunity-scoring" tabindex="-1">Phase 3: Opportunity Scoring <a class="header-anchor" href="#phase-3-opportunity-scoring" aria-label="Permalink to &quot;Phase 3: Opportunity Scoring&quot;">​</a></h3><p>Rate each outcome metric:</p><ul><li><strong>Importance</strong> (1-10): How important is this outcome to the customer?</li><li><strong>Satisfaction</strong> (1-10): How satisfied are they with current solutions?</li><li><strong>Opportunity score</strong> = Importance + max(Importance − Satisfaction, 0)</li></ul><p>Scores ≥ 15 = underserved outcomes → highest priority to address.</p><h2 id="output" tabindex="-1">Output <a class="header-anchor" href="#output" aria-label="Permalink to &quot;Output&quot;">​</a></h2><p>Save JTBD canvas to <code>docs/jtbd/jtbd-canvas-[date].md</code>.</p><h2 id="integration" tabindex="-1">Integration <a class="header-anchor" href="#integration" aria-label="Permalink to &quot;Integration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Relationship</th></tr></thead><tbody><tr><td><code>cm-brainstorm-idea</code></td><td>UPSTREAM: JTBD feeds into strategic analysis</td></tr><tr><td><code>cm-planning</code></td><td>DOWNSTREAM: Validated jobs inform feature plans</td></tr><tr><td><code>cro-methodology</code></td><td>COMPLEMENT: JTBD objections → CRO objection handling</td></tr><tr><td><code>cm-dockit</code></td><td>OUTPUT: JTBD canvases are a document type in DocKit</td></tr></tbody></table>`,25)])])}const b=s(o,[["render",r]]);export{h as __pageData,b as default};
